prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_592364d0_3782_4d34_bcb3_5a37f16f70e4> .
  OPTIONAL { ?task bbo:name ?taskName . }
  FILTER NOT EXISTS {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-DCADED5A-2030-47D6-BD19-E897F75FA853>
      ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?reachable WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_592364d0_3782_4d34_bcb3_5a37f16f70e4> .
  OPTIONAL { ?task bbo:name ?taskName . }
  BIND(EXISTS {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-DCADED5A-2030-47D6-BD19-E897F75FA853>
      ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  } AS ?reachable)
}
ORDER BY ?taskName
